// Validate inputs from a multipart/form-data webhook upload.
// Expected form fields:
//   file         (binary, required)  — image file
//   menu_item_id (text,   required)  — int FK into public.menu_items
//   sort_order   (text,   optional)  — defaults to 0
//
// Generates a UUID-style S3 key and passes the binary through unchanged.
const input = $input.first();
const body = (input.json && input.json.body) || {};
const binaries = input.binary || {};

const binKey = Object.keys(binaries)[0];
if (!binKey) {
  return [{ json: { ok: false, error: 'no file uploaded (expected multipart field with a binary)' } }];
}
const bin = binaries[binKey];
const mime = String(bin.mimeType || '').toLowerCase();
const allowed = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
if (!allowed.includes(mime)) {
  return [{ json: { ok: false, error: 'unsupported mime: ' + mime + ' (allowed: ' + allowed.join(', ') + ')' } }];
}
const extMap = { 'image/jpeg': 'jpg', 'image/png': 'png', 'image/webp': 'webp', 'image/gif': 'gif' };
const ext = extMap[mime];

const menuItemId = parseInt(body.menu_item_id ?? body.menuItemId, 10);
if (!Number.isFinite(menuItemId) || menuItemId <= 0) {
  return [{ json: { ok: false, error: 'menu_item_id required (positive integer)' } }];
}
const sortOrder = parseInt(body.sort_order ?? body.sortOrder ?? '0', 10) || 0;

// UUID-ish key from time + Math.random (no crypto needed; collision risk negligible at our volume)
const rand = () => Math.random().toString(36).slice(2, 10);
const uuid = `${Date.now().toString(36)}-${rand()}-${rand()}`;
const s3Key = `menu/${uuid}.${ext}`;
const publicUrl = `https://foodservai-menu-photos.s3.us-east-2.amazonaws.com/${s3Key}`;

return [{
  json: { ok: true, s3Key, publicUrl, menuItemId, sortOrder, mime, binKey },
  binary: binaries
}];

